  "visual_requirements": [
    "2D cartoon art style.",
    "Parallax scrolling or static background with moving elements to simulate tank tread movement.",
    "Explosion and smoke particle effects when projectiles hit.",
    "Visual degradation of castles as they take damage (e.g., walls breaking away).",
    "Projectile trails.",
    "UI overlays for health bars and unit selection."
  ],
  "prototype_must_have": [
    "Two castles with overall health bars.",
    "Ability to drag and drop at least one unit type into predefined slots on the player's castle.",
    "Units automatically firing projectiles at the enemy castle.",
    "Projectiles dealing damage and reducing castle health.",
    "A win/loss state when a health bar reaches 0."
  ],
  "prototype_can_skip": [
    "Complex visual degradation of the castles (walls breaking away dynamically).",
    "Multiple unit types (one is sufficient for testing the core loop).",
    "Elaborate particle systems for explosions.",
    "Post-match reward screens and menus."
  ],
  "implementation_notes": [
    "Define invisible drop zones (hitboxes) within the Blue Castle sprite for unit placement.",
    "Use a simple state machine for units: 'In UI', 'Being Dragged', 'Placed/Firing'.",
    "Projectiles can be implemented with simple linear interpolation (lerp) or basic physics velocity towards the enemy castle's bounding box.",
    "Castle health can be a single global variable per side, ignoring individual room health for the prototype."
  ],
  "uncertainties": [
    {
      "question": "Do individual units have their own health, or do they die based on the castle's overall damage state?",
      "why_it_matters": "Affects whether units need their own health tracking and hit detection, or if they are just visual representations of the castle's attack power.",
      "confidence": 0.7
    },
    {
      "question": "Are the castles actually moving forward, or is the background scrolling to create the illusion of movement?",
      "why_it_matters": "Determines if the camera and physics need to handle moving objects or just a scrolling background.",
      "confidence": 0.8
    }
  ]
